13	// limitations under the License.
14	//
15	// Author: Brad Hyslop <bhyslop@scaleinvariant.org>
16	//
17	// RBTD Theurge — test orchestrator entry point
18	//
19	// Subcommands:
20	//   rbtd <manifest> <fixture>
21	//     Suite runner — verify manifest, charge, run all cases, quench.
22	//   rbtd single <manifest> <fixture> [case]
23	//     Single-case runner — no charge/quench. List cases or run one.
24	
25	use std::process::ExitCode;
26	
27	use rbtd::rbtdrc_crucible::{
28	    rbtdrc_fixture_fail_fast, rbtdrc_needs_charge, rbtdrc_needs_readiness_delay,
29	    rbtdrc_sections_for_fixture, rbtdrc_set_context, rbtdrc_take_context,
30	    RBTDRC_SERVICE_READINESS_DELAY_SECS,
31	};
32	use rbtd::rbtdre_engine::{
33	    rbtdre_detect_colors, rbtdre_find_case, rbtdre_list_cases, rbtdre_print_summary,
34	    rbtdre_run_sections, rbtdre_run_single_case,
35	};
36	use rbtd::rbtdri_invocation::{rbtdri_Context, rbtdri_invoke, rbtdri_invoke_global};
37	use rbtd::rbtdrm_manifest::{
38	    rbtdrm_verify, RBTDRM_COLOPHON_CHARGE, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
39	    RBTDRM_COLOPHON_QUENCH,
40	};
41	
42	fn main() -> ExitCode {
43	    let args: Vec<String> = std::env::args().collect();
44	
45	    if args.get(1).map(|s| s.as_str()) == Some("single") {
46	        return run_single(&args[2..]);
47	    }
48	
49	    run_suite(&args[1..])
50	}
51	
52	// ── Suite runner ─────────────────────────────────────────────
53	
54	fn run_suite(args: &[String]) -> ExitCode {
55	    let manifest = match args.first() {
56	        Some(m) => m,
57	        None => {
58	            eprintln!(
59	                "rbtd: usage: rbtd <manifest> <fixture>\n\
60	                 theurge must be launched via tabtarget (e.g. tt/rbtd-r.Run.tadmor.sh)"
61	            );
62	            return ExitCode::FAILURE;
63	        }
64	    };
65	
66	    let fixture = match args.get(1) {
67	        Some(n) => n,
68	        None => {
69	            eprintln!("rbtd: no fixture argument — which test fixture to run?");
70	            return ExitCode::FAILURE;
71	        }
72	    };
73	
74	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
75	        eprintln!("{}", msg);
76	        return ExitCode::FAILURE;
77	    }
78	
79	    let project_root = match std::env::current_dir() {
80	        Ok(p) => p,
81	        Err(e) => {
82	            eprintln!("rbtd: cannot determine working directory: {}", e);
83	            return ExitCode::FAILURE;
84	        }
85	    };
86	
87	    let root_temp = std::env::temp_dir().join(format!("rbtd-{}", std::process::id()));
88	    if let Err(e) = std::fs::create_dir_all(&root_temp) {
89	        eprintln!("rbtd: failed to create temp dir: {}", e);
90	        return ExitCode::FAILURE;
91	    }
92	
93	    let burv_root = root_temp.join("burv");
94	    let mut ctx = rbtdri_Context::new(&project_root, fixture, &burv_root);
95	    let needs_charge = rbtdrc_needs_charge(fixture);
96	
97	    // ── Charge crucible (crucible fixtures only) ─────────────
98	    if needs_charge {
99	        eprintln!("\nCharging crucible for nameplate '{}'...", fixture);
100	        match rbtdri_invoke(&mut ctx, RBTDRM_COLOPHON_CHARGE, &[]) {
101	            Ok(r) if r.exit_code == 0 => {
102	                eprintln!("Crucible charged");
103	            }
104	            Ok(r) => {
105	                eprintln!(
106	                    "Charge failed (exit {})\n{}",
107	                    r.exit_code, r.stderr
108	                );
109	                return ExitCode::FAILURE;
110	            }
111	            Err(e) => {
112	                eprintln!("Charge invocation failed: {}", e);
113	                return ExitCode::FAILURE;
114	            }
115	        }
116	
117	        // Lifecycle assertion: crucible must be active after charge
118	        eprintln!("Verifying crucible is active after charge...");
119	        match rbtdri_invoke_global(&mut ctx, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE, &[fixture], &[]) {
120	            Ok(r) if r.exit_code == 0 => {
121	                eprintln!("Crucible active confirmed");
122	            }
123	            Ok(r) => {
124	                eprintln!(
125	                    "Lifecycle assertion failed: crucible not active after charge (exit {})\n{}",
126	                    r.exit_code, r.stderr
127	                );
128	                return ExitCode::FAILURE;
129	            }
130	            Err(e) => {
131	                eprintln!("CrucibleActive invocation failed after charge: {}", e);
132	                return ExitCode::FAILURE;
133	            }
134	        }
135	
136	        // Service readiness delay (srjcl/pluml need services to start)
137	        if rbtdrc_needs_readiness_delay(fixture) {
138	            eprintln!(
139	                "Waiting {}s for service readiness...",
140	                RBTDRC_SERVICE_READINESS_DELAY_SECS
141	            );
142	            std::thread::sleep(std::time::Duration::from_secs(
143	                RBTDRC_SERVICE_READINESS_DELAY_SECS,
144	            ));
145	        }
146	    }
147	
148	    // ── Run cases ────────────────────────────────────────────
149	    let sections = rbtdrc_sections_for_fixture(fixture);
150	    rbtdrc_set_context(ctx);
151	
152	    let colors = rbtdre_detect_colors();
153	    let fail_fast = rbtdrc_fixture_fail_fast(fixture);
154	    let run_result = rbtdre_run_sections(sections, &colors, fail_fast, &root_temp);
155	
156	    // ── Quench crucible (crucible fixtures only, unconditional) ──
157	    let mut ctx = rbtdrc_take_context();
158	    if needs_charge {
159	        eprintln!("\nQuenching crucible...");
160	        match rbtdri_invoke(&mut ctx, RBTDRM_COLOPHON_QUENCH, &[]) {
